"use strict";(self.webpackChunkdocusaurus_knowledge_base=self.webpackChunkdocusaurus_knowledge_base||[]).push([[19820],{61714(e,t,n){n.r(t),n.d(t,{assets:()=>s,contentTitle:()=>c,default:()=>u,frontMatter:()=>a,metadata:()=>r,toc:()=>d});let r=JSON.parse('{"id":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 17 Insurance Contracts/transfer-of-insurance-coverage-under-15cb0d63cc","title":"Transfer of Insurance Coverage under a Group of Annuity Contracts (IFRS 17)","description":"July 2022","source":"@site/knowledge/6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 17 Insurance Contracts/Transfer of Insurance Coverage under a Group of Annuity Contracts (IFRS 17).md","sourceDirName":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 17 Insurance Contracts","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-17-insurance-contracts-e123436304/transfer-of-insurance-coverage-under-15cb0d63cc","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-17-insurance-contracts-e123436304/transfer-of-insurance-coverage-under-15cb0d63cc","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":1,"frontMatter":{"id":"transfer-of-insurance-coverage-under-15cb0d63cc","title":"Transfer of Insurance Coverage under a Group of Annuity Contracts (IFRS 17)","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-17-insurance-contracts-e123436304/transfer-of-insurance-coverage-under-15cb0d63cc","sidebar_position":1},"sidebar":"knowledgeSidebar","previous":{"title":"Lease Term and Useful Life of Leasehold Improvements (IFRS 16 and IAS 16)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-16-and-ias-16-0a501fafe8/lease-term-and-useful-life-of-leaseh-8191c9e768"},"next":{"title":"Multi-currency Groups of Insurance Contracts (IFRS 17 and IAS 21)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-17-and-ias-21-6f301e9ffb/multi-currency-groups-of-insurance-c-7eba702cb6"}}');var i=n(74848),o=n(28453);let a={id:"transfer-of-insurance-coverage-under-15cb0d63cc",title:"Transfer of Insurance Coverage under a Group of Annuity Contracts (IFRS 17)",slug:"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-17-insurance-contracts-e123436304/transfer-of-insurance-coverage-under-15cb0d63cc",sidebar_position:1},c,s={},d=[];function h(e){let t={p:"p",strong:"strong",table:"table",tbody:"tbody",td:"td",th:"th",thead:"thead",tr:"tr",...(0,o.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(t.p,{children:"July 2022"}),"\n",(0,i.jsx)(t.p,{children:"The Committee received a request about a group of annuity contracts. The request asked how an entity determines the amount of the contractual service margin to recognise in\nprofit or loss in a period because of the transfer of insurance coverage for survival in that period."}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"Fact pattern"}),"\nThe request described a group of annuity contracts under which the policyholder of each contract:\na. pays the premium up front and has no right to cancel the contract or seek a refund;\nb. receives a periodic payment from the start of the annuity period for as long as the policyholder survives (for example, a fixed amount of CU100 for each year that the policyholder survives); and\nc. receives no other services under the contract (for example, no other types of insurance coverage or investment-return service)."]}),"\n",(0,i.jsx)(t.p,{children:"The fact pattern referred to groups of contracts for which the annuity period starts immediately after contract inception (\u2018immediate annuity\u2019) and also those for which the\nannuity period starts on a specified date after contract inception (\u2018deferred annuity\u2019)\u2014for example, a contract entered into in 2022 for which the annuity period starts in 2042."}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"Applicable requirements in IFRS 17"}),"\nParagraph 44(e) of IFRS 17 requires an entity to adjust the carrying amount of the contractual service margin for the amount recognised as insurance revenue because of\nthe transfer of insurance contract services in the period. The entity determines this amount by allocating the contractual service margin over the current and remaining\ncoverage period applying paragraph B119 of IFRS 17."]}),"\n",(0,i.jsx)(t.p,{children:"Paragraph B119 of IFRS 17 states that an entity recognises in profit or loss in each period an amount of the contractual service margin to reflect the insurance contract services\nprovided under the group of insurance contracts in that period. The amount is determined by:"}),"\n",(0,i.jsx)(t.p,{children:"a. identifying the coverage units in the group. The number of coverage units in a group is the quantity of insurance contract services provided by the contracts in the group, determined by considering for each contract the quantity of the benefits provided under a contract and its expected coverage period.\nb. allocating the contractual service margin at the end of the period equally to each coverage unit provided in the current period and expected to be provided in the future.\nc. recognising in profit or loss the amount allocated to coverage units provided in the period."}),"\n",(0,i.jsx)(t.p,{children:"The definition of insurance contract services in Appendix A to IFRS 17 describes insurance coverage as \u2018coverage for an insured event\u2019. An insured event is defined as \u2018an uncertain future event covered by an insurance contract that creates insurance risk\u2019."}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"Methods for applying the requirements to the fact pattern"}),"\nThe request sets out two methods of determining, for each contract in the group, the quantity of the benefits of insurance coverage provided in the current period and expected to be provided in the future."]}),"\n",(0,i.jsx)(t.p,{children:"Method 1"}),"\n\n\n\n\n\n\n\n\n\n\n\n\n\n",(0,i.jsxs)(t.table,{children:[(0,i.jsx)(t.thead,{children:(0,i.jsxs)(t.tr,{children:[(0,i.jsx)(t.th,{children:"Current period"}),(0,i.jsx)(t.th,{children:"Expected to be provided in the future"})]})}),(0,i.jsx)(t.tbody,{children:(0,i.jsxs)(t.tr,{children:[(0,i.jsx)(t.td,{children:"Determined based on the annuity payment the policyholder is able to validly claim in the current period."}),(0,i.jsx)(t.td,{children:"Determined based on the present value of the annuity payments the policyholder is expected to be able to validly claim in the future until the end of the coverage period (the balance of the expected future annuity  payments as at the end of the current period)."})]})})]}),"\n",(0,i.jsx)(t.p,{children:"Method 2"}),"\n\n\n\n\n\n\n\n\n\n\n\n\n\n",(0,i.jsxs)(t.table,{children:[(0,i.jsx)(t.thead,{children:(0,i.jsxs)(t.tr,{children:[(0,i.jsx)(t.th,{children:"Current period"}),(0,i.jsx)(t.th,{children:"Expected to be provided in the future"})]})}),(0,i.jsx)(t.tbody,{children:(0,i.jsxs)(t.tr,{children:[(0,i.jsx)(t.td,{children:"Determined based on the total of: (i) the annuity payment the policyholder is able to validly claim in the current period, and (ii) the present value of the annuity payments the policyholder is expected to be able to validly claim in the future until the end of the coverage period (the balance of the expected future annuity payments as at the end of the current period)."}),(0,i.jsx)(t.td,{children:"Determined based on the present value of the balances of the expected future annuity payments as at the beginning of each future period, until the end of the coverage period."})]})})]}),"\n",(0,i.jsx)(t.p,{children:(0,i.jsx)(t.strong,{children:"Applying paragraph B119 of IFRS 17"})}),"\n",(0,i.jsx)(t.p,{children:"Applying paragraph B119(a) of IFRS 17, an entity:\na. identifies the insurance contract services to be provided under the group of contracts. In the fact pattern described in the request, insurance coverage for survival is the only insurance contract service provided under the group of contracts.\nb. considers the expected coverage period for each contract in the group. In the fact pattern described in the request, the expected coverage period would reflect the entity\u2019s expectations of how long the policyholder will survive.\nc. considers the quantity of the benefits provided under each contract in the group."}),"\n",(0,i.jsx)(t.p,{children:"IFRS 17 does not prescribe a method for determining the quantity of the benefits provided under a contract. Instead, an entity is required to use a method that meets the principle in paragraph B119 of reflecting the insurance contract services provided in each period. In selecting a method that meets that principle, an entity considers (a) the benefits  provided to the policyholder under a contract with respect to the insurance contract services provided, and (b) when those benefits are provided. Different methods may achieve the principle depending on the facts and circumstances."}),"\n",(0,i.jsx)(t.p,{children:"In the fact pattern described in the request, the terms of the annuity contract provide the policyholder with the right to claim a periodic amount (CU100 in the example) from the\nstart of the annuity period for as long as the policyholder survives. Consequently, the Committee observed that:"}),"\n",(0,i.jsx)(t.p,{children:"a. the benefits provided to the policyholder under the contract with respect to the insurance coverage for survival are the policyholder\u2019s right to claim a periodic amount for as long as they survive. The policyholder also benefits from transferring to the entity the risk related to the uncertainty about how long they will survive. However, IFRS 17 requires an entity to account for that insurance risk in the risk adjustment for non-financial risk, separately from the contractual service margin.\nb. the benefits of being able to claim a periodic amount are provided to the policyholder in each year of the policyholder\u2019s survival from the start of the annuity period:\ni. the policyholder has no right to claim an amount for surviving in periods before the start of the annuity period. The entity accepts insurance risk from inception of the contract but provides no benefits to the policyholder in the form of amounts that can be claimed until the annuity period starts. Paragraphs BC140\u2013BC141 of the Basis for Conclusions on IFRS 17 explain that an entity can accept insurance risk before it is obliged to perform an insurance coverage service.\nii. survival in one year does not provide the policyholder with the right to claim amounts that compensate the policyholder for surviving in future years; that is, the policyholder\u2019s right to claim amounts in future years is contingent on the policyholder surviving in those future years."}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"The Committee\u2019s conclusion"}),"\nThe Committee concluded that, in applying IFRS 17 to determine the quantity of the benefits of insurance coverage for survival provided under each annuity contract, a\nmethod based on:\na. the amount of the annuity payment the policyholder is able to validly claim (Method 1) meets the principle in paragraph B119 of IFRS 17 of reflecting the\ninsurance coverage provided in each period by:\ni. assigning a quantity of the benefits only to periods in which an insured event (survival of the policyholder) can occur, resulting in a policyholder having a right to make a valid claim; and\nii. aligning the quantity of the benefits provided in a period with the amount the policyholder is able to validly claim if an insured event occurs in that period.\nb. the present value of expected future annuity payments (Method 2) does not meet the principle in paragraph B119 of IFRS 17 of reflecting the insurance coverage provided in each period because it would:\ni. assign a quantity of the benefits to periods in which no insured event occurs (for example, to the deferral period of a deferred annuity contract); and\nii. misrepresent the quantity of the benefits provided in a period by considering amounts the policyholder is able to claim and benefit from only in future periods."]}),"\n",(0,i.jsx)(t.p,{children:"The request asked only about the recognition of the contractual service margin in profit or loss. For the annuity contracts described in the request, the entity accepts insurance risk related to the uncertainty about how long the policyholder will survive. The Committee noted that the entity would apply other requirements in IFRS 17 to recognise in profit or loss\u2014separately from the contractual service margin\u2014the risk adjustment for non-financial risk. The risk adjustment for non-financial risk represents the compensation the entity requires for bearing the uncertainty about the amount and timing of the cash flows that arise from non-financial risk. The Committee did not discuss these other requirements."}),"\n",(0,i.jsx)(t.p,{children:"Under a group of annuity contracts, an entity could provide other insurance contract services to policyholders in addition to insurance coverage for survival\u2014for example,\ninsurance coverage for death in a deferral period or an investment-return service. The conclusion in this agenda decision applies to insurance coverage for survival, regardless\nof other services provided. If the contracts provide other insurance contract services, the entity would also need to consider the pattern of transfer of these services to the\npolicyholder."}),"\n",(0,i.jsx)(t.p,{children:"The Committee concluded that the principles and requirements in IFRS Accounting Standards provide an adequate basis for an issuer of a group of annuity contracts as\ndescribed in the request to determine the amount of the contractual service margin to recognise in profit or loss in a period because of the transfer of insurance coverage for\nsurvival in that period. Consequently, the Committee decided not to add a standard-setting project to the work plan."})]})}function u(e={}){let{wrapper:t}={...(0,o.R)(),...e.components};return t?(0,i.jsx)(t,{...e,children:(0,i.jsx)(h,{...e})}):h(e)}},28453(e,t,n){n.d(t,{R:()=>a,x:()=>c});var r=n(96540);let i={},o=r.createContext(i);function a(e){let t=r.useContext(o);return r.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function c(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:a(e.components),r.createElement(o.Provider,{value:t},e.children)}}}]);